INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('multiple_choice', '2021 年11 月16 日，习近平就《中共中央关于党的百年奋斗重大成就和历史经验的决议》起草的有关情况向全会作说明，概括了其具有根本性和长远指导意义的十条历史经验，揭示了:', 'ABCD', '[{"key": "A", "value": "党和人民事业不断成功的根本保证"}, {"key": "B", "value": "党始终立于不败之地的力量源泉"}, {"key": "C", "value": "党始终掌握历史主动的根本原因"}, {"key": "D", "value": "党永葆先进性和纯洁性、始终走在时代前列的根本途径"}]', '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('multiple_choice', '2021 年11 月16 日，习近平就《中共中央关于党的百年奋斗重大成就和历史经验的决议》起草的有关情况向全会作说明，全面总结党的百年奋斗重大成就和历史经验，是郑重的历史性、战略性决策，充分体现:', 'ABD', '[{"key": "A", "value": "党牢记初心使命、永葆生机活力的坚强意志和坚定决心"}, {"key": "B", "value": "党深刻把握历史发展规律、始终掌握党和国家事业发展的历史主动和使命担当"}, {"key": "C", "value": "加强党的领导这个马克思主义政党的鲜明特征和政治优势"}, {"key": "D", "value": "党立足当下、着眼未来、注重总结和运用历史经验的高瞻远瞩和深谋远虑"}]', '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('multiple_choice', '2021 年11 月16 日，习近平就《中共中央关于党的百年奋斗重大成就和历史经验的决议》起草的有关情况向全会作说明，对这次全会决议起草，党中央明确要求着重把握好以下几点:', 'ACD', '[{"key": "A", "value": "聚焦总结党的百年奋斗重大成就和历史经验"}, {"key": "B", "value": "突出党的政治建设这个重点"}, {"key": "C", "value": "突出中国特色社会主义新时代这个重点"}, {"key": "D", "value": "对重大事件、重要会议、重要人物的评价注重同党中央已有结论相衔接"}]', '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('multiple_choice', '2022 年5 月10 日，庆祝中国共产主义青年团成立100 周年大会隆重举行。习近平强调，在新的征程上，( )，( )，是新时代中国青年运动和青年工作必须回答的重大课题。', 'AD', '[{"key": "A", "value": "如何更好地把青年团结起来、组织起来、动员起来"}, {"key": "B", "value": "如何坚定青年理想"}, {"key": "C", "value": "为实现共产主义而奋斗"}, {"key": "D", "value": "为实现第二个百年奋斗目标、实现中华民族伟大复兴的中国梦而奋斗"}]', '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('multiple_choice', '为顺应时代发展，以习近平同志为主要代表的中国共产党人，从理论和实践结合上系统回答了新时代重大时代课题，创立了( )的习近平新时代中国特色社会主义思想。', 'AC', '[{"key": "A", "value": "怎样坚持和发展中国特色社会主义"}, {"key": "B", "value": "怎样建设社会主义和建设什么样的党"}, {"key": "C", "value": "坚持和发展什么样的中国特色社会主义"}, {"key": "D", "value": "怎样建设党"}]', '', NOW(), NOW());
