INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('multiple_choice', '党在自己的工作中实行群众路线，把党的正确主张变为群众的自觉行动。( )', 'ABCD', '[{"key": "A", "value": "一切为了群众"}, {"key": "B", "value": "一切依靠群众"}, {"key": "C", "value": "从群众中来"}, {"key": "D", "value": "到群众中去"}]', '', NOW(), NOW());
