INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('multiple_choice', '党的二十大报告指出，只有把( )同中国( )相结合、同( )相结合，坚持运用辩证唯物主义和历史唯物主义，才能正确回答时代和实践提出的重大问题，才能始终保持马克思主义的蓬勃生机和旺盛活力。', 'ACD', '[{"key": "A", "value": "马克思主义基本原理"}, {"key": "B", "value": "新时代中国特色社会主义"}, {"key": "C", "value": "具体实际"}, {"key": "D", "value": "中华优秀传统文化"}]', '', NOW(), NOW());
