INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('multiple_choice', '增强维护国家安全能力，坚定维护国家( )确保粮食、能源资源、重要产业链供应链安全，维护我国公民、法人在海外合法权益，筑牢国家安全人民防线。', 'ABCD', '[{"key": "A", "value": "政治安全"}, {"key": "B", "value": "政权安全"}, {"key": "C", "value": "制度安全"}, {"key": "D", "value": "意识形态安全"}]', '', NOW(), NOW());